class Solution {
    public boolean equalFrequency(String word) {
        int[] freq = new int[26];
        for (char c : word.toCharArray()) {
            freq[c - 'a']++;
        }
        int count = 0;
        int target = -1;
        for (int f : freq) {
            if (f > 0) {
                if (target == -1) {
                    target = f;
                } else if (target != f) {
                    count++;
                }
            }
        }
        return count <= 1;
    }
}
```
